CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_atm_recv_file_head() RETURNS trigger AS $BODY$
BEGIN

  if coalesce(OLD.OPERATE_DATE::text, '') = '' and (NEW.OPERATE_DATE IS NOT NULL AND NEW.OPERATE_DATE::text <> '') then
    if pka.auto_entry then 
      NEW.entry_id := current_setting('app.login_id', true);
      NEW.entry_br := current_setting('app.login_br', true);
      NEW.entry_pc := pka_com_login.login_pc;
      NEW.entry_date := statement_timestamp();
    end if;
  end if;

  if (coalesce(NEW.operate_time::text, '') = '' or NEW.operate_time = ' ') and coalesce(OLD.operate_time::text, '') = '' then
    -- ต้องทำรายการครั้งเดียวเท่านั้น
    NEW.operate_time := to_char(statement_timestamp(),'YYYY-MM-DD HH24:MI:SS.MS');
  end if;

  if coalesce(NEW.total_recode::text, '') = '' then NEW.total_recode :=0;end if;
  if coalesce(NEW.total_detail::text, '') = '' then NEW.total_detail :=0;end if;
  if coalesce(NEW.analy_status::text, '') = '' or NEW.analy_status =' ' then NEW.analy_status :='0';end if;
  if coalesce(NEW.analy_tot_success::text, '') = '' then NEW.analy_tot_success :=0;end if;
  if coalesce(NEW.analy_tot_failure::text, '') = '' then NEW.analy_tot_failure :=0;end if;
  if coalesce(NEW.post_status::text, '') = '' or NEW.post_status =' ' then NEW.post_status :='0';end if;
  if coalesce(NEW.post_tot_success::text, '') = '' then NEW.post_tot_success :=0;end if;
  if coalesce(NEW.post_tot_failure::text, '') = '' then NEW.post_tot_failure :=0;end if;
  if coalesce(NEW.cancel_status::text, '') = '' then NEW.cancel_status := '0';end if;

  if OLD.cancel_status = '0' and NEW.cancel_status = '1' then
    NEW.cancel_id := current_setting('app.login_id', true);
    NEW.cancel_br := current_setting('app.login_br', true);
  end if;

RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
